class Solution:
    def canIWin(self, maxChoosableInteger: int, desiredTotal: int) -> bool:
        def dfs(usedNumbers, currentTotal):
            for i in range(1, maxChoosableInteger + 1):
                if not (usedNumbers & (1 << i)):
                    if currentTotal + i >= desiredTotal:
                        return True
                    if not dfs(usedNumbers | (1 << i), currentTotal + i):
                        return True
            return False
        return dfs(0, 0) if desiredTotal <= (maxChoosableInteger + 1) * maxChoosableInteger // 2 else False
